export interface SceneLoaderStaticsDetails {
    name: string;
    url: string;
    /**
     * 加载JSON耗时
     */
    loadJSON?: number;
    /**
     * 加载二进制耗时
     */
    loadBins?: number;
    /**
     * 加载图片耗时
     */
    loadImages?: number;
    /**
     * 编译总耗时
     */
    precompile?: number;
    /**
     * 加载texture阶段耗时
     */
    loadTextures?: number;
    /**
     * 插件加载整体时间
     */
    loadPlugins?: number;
    timestamps?: string;
    /**
     * 插件的具体加载信息，每个插件的加载时间，按照插件名称进行记录
     */
    plugins: {
        /**
         * 插件加载资源
         */
        resource?: Record<string, number>;
        /**
         * 插件编译
         */
        compile?: Record<string, number>;
    };
    /**
     * 加载总耗时
     */
    total: number;
}
